SELECT 
  ROUND(AVG(precinct_turnout_percentage), 2) AS average_turnout_percentage
FROM precincts;

SELECT candidate_name 
FROM candidates 
WHERE LENGTH(candidate_bio) = ( 
  SELECT MAX(LENGTH(candidate_bio)) 
  FROM candidates 
);

SELECT AVG(turnout_percentage) AS average_turnout
FROM voter_turnout
WHERE fips IN (SELECT fips FROM precincts WHERE precinct_voting_machines > 100);
